import json
import re
import xml.etree.ElementTree as ET
from datetime import datetime, timezone, timedelta

# Shuffle injecte les variables HTTP comme des littéraux Python (dict, pas str JSON)
# Ces aliases évitent les NameError sur les valeurs JSON true/false/null
true = True
false = False
null = None

MONTHS = {
    'Jan':1,'Feb':2,'Mar':3,'Apr':4,'May':5,'Jun':6,
    'Jul':7,'Aug':8,'Sep':9,'Oct':10,'Nov':11,'Dec':12
}

def get_body(raw):
    """Extrait le champ 'body' de la réponse HTTP Shuffle.
    raw peut être un dict Python (injection directe Shuffle)
    ou une str JSON (fallback).
    Retourne le body tel quel : str pour XML, dict pour JSON KEV.
    """
    if isinstance(raw, dict):
        return raw.get('body', '')
    if isinstance(raw, str):
        try:
            obj = json.loads(raw)
            return obj.get('body', raw)
        except Exception:
            return raw
    return ''

def parse_xml(body_str):
    """Parse une chaîne XML en Element, en gérant la déclaration d'encodage."""
    if not isinstance(body_str, str) or not body_str.strip():
        return None
    # Supprime la déclaration <?xml ...?> pour éviter les conflits d'encodage
    clean = re.sub(r'^\s*<\?xml[^>]*\?>', '', body_str).strip()
    try:
        return ET.fromstring(clean)
    except Exception:
        try:
            return ET.fromstring(body_str.encode('utf-8'))
        except Exception:
            return None

def parse_rfc2822(s):
    try:
        m = re.search(
            r'(\d{1,2})\s+([A-Za-z]{3})\s+(\d{4})\s+(\d{2}):(\d{2}):(\d{2})\s+([+-]\d{4}|GMT|UTC|Z)',
            s.strip()
        )
        if m:
            d, mon, y, h, mi, sec, tz = m.groups()
            if tz in ('GMT', 'UTC', 'Z'):
                off = timedelta(0)
            else:
                sign = 1 if tz[0] == '+' else -1
                off = timedelta(hours=int(tz[1:3]), minutes=int(tz[3:5])) * sign
            return datetime(
                int(y), MONTHS.get(mon, 1), int(d),
                int(h), int(mi), int(sec),
                tzinfo=timezone(off)
            ).astimezone(timezone.utc)
    except Exception:
        pass
    return None

def strip_html(text):
    if not text:
        return ''
    text = re.sub(r'<[^>]+>', ' ', text)
    for ent, rep in [('&amp;','&'),('&lt;','<'),('&gt;','>'),('&quot;','"'),('&nbsp;',' ')]:
        text = text.replace(ent, rep)
    text = re.sub(r'&#\d+;', '', text)
    return re.sub(r'\s+', ' ', text).strip()

def extract_cves(text):
    found = re.findall(r'CVE-\d{4}-\d{4,7}', text, re.IGNORECASE)
    return list(dict.fromkeys(c.upper() for c in found))

def parse_rss(raw, source_name, cutoff_dt):
    items = []
    try:
        body = get_body(raw)
        root = parse_xml(body)
        if root is None:
            return items
        channel = root.find('channel')
        if channel is None:
            channel = root
        for item in channel.findall('item'):
            try:
                title = (item.findtext('title') or '').strip()[:200]
                link  = (item.findtext('link') or '').strip()
                if not link:
                    guid_el = item.find('guid')
                    if guid_el is not None:
                        link = (guid_el.text or '').strip()
                pub_raw = (item.findtext('pubDate') or '').strip()
                desc    = item.findtext('description') or ''
                summary = strip_html(desc)[:500]
                dt = parse_rfc2822(pub_raw)
                if dt is not None:
                    if dt < cutoff_dt:
                        continue
                    date_str = dt.strftime('%Y-%m-%dT%H:%M:%SZ')
                else:
                    date_str = pub_raw
                cves = extract_cves(title + ' ' + summary)
                items.append({
                    'source':  source_name,
                    'title':   title,
                    'link':    link,
                    'summary': summary,
                    'date':    date_str,
                    'cves':    cves,
                    'in_kev':  False,
                    'kev_due': ''
                })
            except Exception:
                continue
    except Exception:
        pass
    return items

# ── Fenêtres temporelles ──────────────────────────────────────────────────────
now_utc    = datetime.now(timezone.utc)
cutoff_24h = now_utc - timedelta(hours=24)
cutoff_48h = now_utc - timedelta(hours=48)

# ── Variables Shuffle (injectées comme littéraux Python) ──────────────────────
raw_certfr   = $cert-fr_feed
raw_dfir     = $the_dfir_report_feed
raw_talos    = $cisco_talos_feed
raw_bleeping = $bleeping_computer_feed
raw_kev      = $cisa_kev_feed

# ── Parsing RSS ───────────────────────────────────────────────────────────────
all_items = []
all_items += parse_rss(raw_certfr,   'CERT-FR',         cutoff_24h)
all_items += parse_rss(raw_dfir,     'DFIR Report',     cutoff_24h)
all_items += parse_rss(raw_talos,    'Cisco Talos',     cutoff_24h)
all_items += parse_rss(raw_bleeping, 'BleepingComputer',cutoff_24h)

# ── Déduplification par URL ───────────────────────────────────────────────────
seen   = set()
deduped = []
for item in all_items:
    key = item['link'] or item['title']
    if key and key not in seen:
        seen.add(key)
        deduped.append(item)

# ── CISA KEV ──────────────────────────────────────────────────────────────────
full_kev_index = {}  # cveID -> dueDate (tout le catalogue, pour cross-référence)
try:
    kev_body = get_body(raw_kev)
    # kev_body peut être un dict (body JSON déjà parsé par Shuffle) ou une str
    if isinstance(kev_body, dict):
        kev_data = kev_body
    else:
        kev_data = json.loads(kev_body)

    for vuln in kev_data.get('vulnerabilities', []):
        cve_id = (vuln.get('cveID') or '').upper()
        if cve_id:
            full_kev_index[cve_id] = vuln.get('dueDate', '')

    # Entrées ajoutées dans les 48 dernières heures → items dédiés CISA KEV
    for vuln in kev_data.get('vulnerabilities', []):
        date_added_str = vuln.get('dateAdded', '')
        try:
            da = datetime.strptime(date_added_str, '%Y-%m-%d').replace(tzinfo=timezone.utc)
            if da < cutoff_48h:
                continue
        except Exception:
            continue
        cve_id = (vuln.get('cveID') or '').upper()
        link   = f"https://nvd.nist.gov/vuln/detail/{cve_id}"
        if link in seen:
            continue
        seen.add(link)
        deduped.append({
            'source':  'CISA KEV',
            'title':   f"{cve_id}: {vuln.get('vulnerabilityName', '')}",
            'link':    link,
            'summary': (vuln.get('shortDescription') or '')[:500],
            'date':    date_added_str,
            'cves':    [cve_id],
            'in_kev':  True,
            'kev_due': vuln.get('dueDate', '')
        })
except Exception:
    pass

# ── Marquage in_kev sur les items RSS ─────────────────────────────────────────
for item in deduped:
    if item['source'] == 'CISA KEV' or item.get('in_kev'):
        continue
    for cve in item.get('cves', []):
        if cve in full_kev_index:
            item['in_kev']  = True
            item['kev_due'] = full_kev_index[cve]
            break

print(json.dumps(deduped, ensure_ascii=False))

