def he(s):
    return str(s).replace('&','&amp;').replace('<','&lt;').replace('>','&gt;').replace('"','&quot;').replace("'",'&#39;')

def fmt_date(s):
    if len(s) >= 10:
        return s[:10]
    return s

def card_border(item, is_urgent=False):
    if item.get('in_kev') or (item['source'] == 'CERT-FR' and item.get('cves')):
        return 'kev'
    if is_urgent:
        return 'urgent'
    if item.get('cves'):
        return 'has-cve'
    return ''

def render_card(item, is_urgent=False):
    border     = card_border(item, is_urgent)
    title_e    = he(item['title'])
    summary_e  = he(item['summary'])
    link       = he(item['link'])
    date_s     = fmt_date(item['date'])
    source_tag = f'<span class="tag tag-source">{he(item["source"])}</span>'
    cve_tags   = ''.join(
        f'<span class="tag tag-cve">{he(c)}</span>'
        for c in item.get('cves', [])[:5]
    )
    kev_tag = ''
    if item.get('in_kev'):
        due = f' · échéance {he(item["kev_due"])}' if item.get('kev_due') else ''
        kev_tag = f'<span class="tag tag-kev">&#x26A1; KEV{due}</span>'
    return (
        f'<div class="card {border}">'
        f'<div class="card-header">'
        f'<div class="card-title"><a href="{link}" target="_blank" rel="noopener">{title_e}</a></div>'
        f'<div class="card-date">{date_s}</div>'
        f'</div>'
        f'<div class="card-summary">{summary_e}</div>'
        f'<div class="tags">{source_tag}{cve_tags}{kev_tag}</div>'
        f'</div>'
    )

