def build_html(urgent, veille, now):
    all_items = urgent + veille
    sources   = sorted(set(i['source'] for i in all_items))
    all_cves  = set(c for i in all_items for c in i.get('cves', []))
    kev_count = sum(1 for i in all_items if i.get('in_kev'))
    date_s    = now.strftime('%Y-%m-%d')
    time_s    = now.strftime('%H:%M UTC')

    n_urgent = len(urgent)
    if n_urgent == 0:
        urgent_time = "Rien à traiter"
    else:
        urgent_time = f"~{n_urgent * 2} min"

    pills_html = ''.join(f'<span class="pill">{he(s)}</span>' for s in sources)
    if not sources:
        pills_html = '<span class="pill">Aucune source</span>'

    stats_html = (
        f'<div class="stat-card stat-kev"><div class="stat-value">{kev_count}</div>'
        f'<div class="stat-label">KEV actives</div></div>'
        f'<div class="stat-card stat-cve"><div class="stat-value">{len(all_cves)}</div>'
        f'<div class="stat-label">CVE stack</div></div>'
        f'<div class="stat-card stat-urgent"><div class="stat-value">{n_urgent}</div>'
        f'<div class="stat-label">Urgents</div></div>'
        f'<div class="stat-card stat-veille"><div class="stat-value">{len(veille)}</div>'
        f'<div class="stat-label">Veille</div></div>'
    )

    if urgent:
        urgent_html = ''.join(render_card(i, is_urgent=True) for i in urgent)
    else:
        urgent_html = '<div class="empty">Aucune alerte urgente ce jour</div>'

    if veille:
        veille_html = ''.join(render_card(i) for i in veille)
    else:
        veille_html = '<div class="empty">Aucun article en veille ce jour</div>'

    return (
        f'<!DOCTYPE html><html lang="fr"><head>'
        f'<meta charset="UTF-8">'
        f'<meta name="viewport" content="width=device-width,initial-scale=1">'
        f'<title>Daily Security Digest — {date_s}</title>'
        f'<style>{CSS}</style>'
        f'</head><body>'
        f'<div class="header">'
        f'<div><h1>Daily Security Digest</h1><div class="pills">{pills_html}</div></div>'
        f'<div class="header-right">{date_s}<br>{time_s}</div>'
        f'</div>'
        f'<div class="stats">{stats_html}</div>'
        f'<div class="section">'
        f'<div class="section-hdr section-urgent"><span class="badge badge-urgent">&#x26A0; Urgent — {urgent_time}</span></div>'
        f'{urgent_html}'
        f'</div>'
        f'<div class="section">'
        f'<div class="section-hdr section-veille"><span class="badge badge-veille">&#x1F550; Veille — si temps disponible</span></div>'
        f'{veille_html}'
        f'</div>'
        f'<div class="footer">Confidentiel interne &middot; Diffusion restreinte</div>'
        f'</body></html>'
    )

def top_items_field(items, n=3):
    lines = []
    for i in items[:n]:
        title = i['title'][:80] + ('…' if len(i['title']) > 80 else '')
        lines.append(f"[{title}]({i['link']})")
    return '\n'.join(lines) if lines else '—'

def build_discord(urgent, veille, now):
    all_items = urgent + veille
    all_cves  = set(c for i in all_items for c in i.get('cves', []))
    kev_count = sum(1 for i in all_items if i.get('in_kev'))
    date_s    = now.strftime('%Y-%m-%d')
    sources   = sorted(set(i['source'] for i in all_items))

    color = 0xDA3633 if urgent else 0x1F6FEB

    desc_lines = [
        f"**{kev_count} KEV** · **{len(all_cves)} CVE** · **{len(urgent)} urgents** · **{len(veille)} veille**",
        f"Sources : {', '.join(sources) if sources else '—'}"
    ]

    kev_items    = [i for i in urgent if i.get('in_kev')]
    certfr_items = [i for i in urgent if i['source'] == 'CERT-FR']
    other_urgent = [i for i in urgent if not i.get('in_kev') and i['source'] != 'CERT-FR']

    fields = []
    if kev_items:
        fields.append({"name": "⚡ Top KEV", "value": top_items_field(kev_items), "inline": False})
    if certfr_items:
        fields.append({"name": "🔴 Top CERT-FR", "value": top_items_field(certfr_items), "inline": False})
    if other_urgent:
        fields.append({"name": "🔴 Top Alertes", "value": top_items_field(other_urgent), "inline": False})

    embed = {
        "title": f"Daily Security Digest — {date_s}",
        "description": '\n'.join(desc_lines),
        "color": color,
        "fields": fields,
        "footer": {"text": "Shuffle SOAR · Usage SOC interne"}
    }
    return {"embeds": [embed]}

